class TreeNode:
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

def get_height(node):
    """Property: Height of a node is the number of edges on longest path from node to a leaf"""
    if node is None:
        return -1  # Empty tree has height -1; single node has height 0
    return 1 + max(get_height(node.left), get_height(node.right))

def get_size(node):
    """Property: Size is total number of nodes in the tree"""
    if node is None:
        return 0
    return 1 + get_size(node.left) + get_size(node.right)

def count_leaves(node):
    """Property: Leaf nodes are nodes with no children"""
    if node is None:
        return 0
    if node.left is None and node.right is None:
        return 1
    return count_leaves(node.left) + count_leaves(node.right)

def get_depth(node, target, current=0):
    """Property: Depth is the number of edges from root to the node"""
    if node is None:
        return -1
    if node.data == target:
        return current
    left_depth = get_depth(node.left, target, current + 1)
    if left_depth != -1:
        return left_depth
    return get_depth(node.right, target, current + 1)

# Build sample tree
#         1
#        / \
#       2   3
#      / \
#     4   5

root = TreeNode(1)
root.left = TreeNode(2)
root.right = TreeNode(3)
root.left.left = TreeNode(4)
root.left.right = TreeNode(5)

print(f"Height: {get_height(root)}")
print(f"Size (total nodes): {get_size(root)}")
print(f"Number of leaves: {count_leaves(root)}")
print(f"Depth of node 5: {get_depth(root, 5)}")
